(function($) {
    const initializeTimeline = function() {
        const timelineBlock = document.querySelector('.integrated-degree');
        if (timelineBlock) {
            const $cards = $('.integrated-degree-dt  .tl-wrapper');
            $cards.each(function(i, card) {
                if (i === 0) {
                    return
                }
                const base = 80;
                const step = 12.5;
                let triggerPoint = base - ((i - 1) * step);
                if (triggerPoint < 10) {
                    triggerPoint = 10
                }
                ScrollTrigger.create({
                    trigger: card,
                    start: `top+=${ 70 * i }% center`,
                    onEnter: () => {
                        $cards.slice(0, i + 1).addClass('active')
                    },
                    onLeaveBack: () => {
                        $cards.slice(i).removeClass('active')
                    },
                })
            });
            const $cardsTablet = $('.integrated-degree-tablet .tl-wrapper');
            $cardsTablet.each(function(i) {
                setTimeout(() => {
                    $(this).addClass('active')
                }, i * 1000)
            });
            $('.year-accordion-wrapper').on('click', function() {
                const $this = $(this);
                const isActive = $this.hasClass('active');
                $this.parent().find('.year-accordion-wrapper').removeClass('active').addClass('not-active').find('.information-container').stop().slideUp();
                if (isActive) {
                    $this.removeClass('active').addClass('not-active')
                } else {
                    $this.removeClass('not-active').addClass('active')
                }
                const $answer = $(this).find('.information-container');
                $answer.stop().slideToggle()
            })
        }
        setTimeout(() => {
            ScrollTrigger.refresh()
        }, 2000)
    };
    const initializeScrollShrinkImage = function() {
        if (window.innerWidth < 1024) {
            return
        }
        if (typeof gsap === 'undefined' || typeof ScrollTrigger === 'undefined') {
            return
        }
        const htmlLang = document.documentElement.getAttribute('lang') || 'en';
        const gtranslateLang = (() => {
            const row = document.cookie.split('; ').find((r) => r.startsWith('googtrans='));
            if (!row) {
                return null
            }
            const parts = row.split('=');
            if (!parts[1]) {
                return null
            }
            const subParts = parts[1].split('/');
            return subParts[2] || null
        })();
        const activeLang = (gtranslateLang || htmlLang).toLowerCase().split('-')[0];
        const translateYValue = activeLang === 'th' ? 146 : 135;
        const wrappers = document.querySelectorAll('.compact-hero-wrapper');
        wrappers.forEach((wrapper) => {
            const image = wrapper.querySelector('.compact-hero-image');
            if (!image) {
                return
            }
            gsap.to(image, {
                scrollTrigger: {
                    trigger: wrapper,
                    start: '-10% top',
                    end: '+=400',
                    scrub: !0,
                    pin: !0,
                    pinSpacing: !0,
                },
                translateY: translateYValue,
                width: 213,
                height: 76,
                ease: 'none',
            })
        })
    };
    const initializeHeroGalleryRotation = function() {
        const $frames = $('.hero-frame');
        if ($frames.length === 0) {
            return
        }
        let current = 0;
        setInterval(() => {
            $frames.eq(current).removeClass('active');
            current = (current + 1) % $frames.length;
            $frames.eq(current).addClass('active')
        }, 700)
    };
    $(document).ready(function() {
        initializeTimeline();
        initializeScrollShrinkImage();
        initializeHeroGalleryRotation()
    });
    if (window.acf) {
        window.acf.addAction('render_block_preview/type=gl-hero', initializeTimeline);
        window.acf.addAction('render_block_preview/type=gl-hero', initializeScrollShrinkImage);
        window.acf.addAction('render_block_preview/type=gl-hero', initializeHeroGalleryRotation)
    }
}(jQuery));
(function($) {
    let splitInstance;
    const previousWidth = window.innerWidth;

    function debounce(func, wait, immediate = !1) {
        let timeout;
        return function executedFunction(...args) {
            const context = this;
            const later = function() {
                timeout = null;
                if (!immediate) {
                    func.apply(context, args)
                }
            };
            const callNow = immediate && !timeout;
            clearTimeout(timeout);
            timeout = setTimeout(later, wait);
            if (callNow) {
                func.apply(context, args)
            }
        }
    }
    const initBulletVerticalAlign = function() {
        const listItems = document.querySelectorAll('.list .list-item');
        const images = document.querySelectorAll('.feature-image');
        if (!listItems.length || !images.length) {
            return
        }
        let currentIndex = 0;

        function activateItem(index) {
            listItems.forEach((item) => item.classList.remove('active'));
            listItems.forEach((item, i) => {
                const distance = Math.abs(i - index);
                let opacity;
                if (distance === 0) {
                    opacity = 1
                } else if (distance === 1) {
                    opacity = 0.35
                } else if (distance === 2) {
                    opacity = 0.25
                } else if (distance === 3) {
                    opacity = 0.15
                } else {
                    opacity = 0.10
                }
                const mqDesktop = window.matchMedia('(min-width: 1024px)');
                const mqTablet = window.matchMedia('(min-width: 768px) and (max-width: 1023px)');
                const mqMobile = window.matchMedia('(max-width: 767px)');
                if (mqDesktop.matches) {
                    gsap.to(item, {
                        opacity,
                        fontSize: i === index ? '40px' : '32px',
                        lineHeight: i === index ? '48px' : '38.4px',
                        letterSpacing: i === index ? '-1.2px' : '-0.64px',
                        paddingLeft: i === index ? '44px' : '0px',
                        duration: 0.3,
                        ease: 'power1.out',
                    })
                } else if (mqTablet.matches) {
                    gsap.to(item, {
                        opacity,
                        fontSize: i === index ? '30px' : '26px',
                        lineHeight: i === index ? '45px' : '39px',
                        letterSpacing: i === index ? '-0.6px' : '-0.26px',
                        paddingLeft: i === index ? '32px' : '0px',
                        duration: 0.3,
                        ease: 'power1.out',
                    })
                } else if (mqMobile.matches) {
                    gsap.to(item, {
                        opacity,
                        fontSize: i === index ? '22px' : '18px',
                        lineHeight: i === index ? '33px' : '27px',
                        letterSpacing: i === index ? '-0.44px' : '-0.18px',
                        paddingLeft: i === index ? '24px' : '0px',
                        duration: 0.3,
                        ease: 'power1.out',
                    })
                }
            });
            gsap.delayedCall(0.2, () => {
                listItems[index].classList.add('active');
                images.forEach((img, i) => {
                    img.classList.toggle('opacity-100', i === index);
                    img.classList.toggle('z-10', i === index);
                    img.classList.toggle('opacity-0', i !== index);
                    img.classList.toggle('z-0', i !== index)
                })
            })
        }
        activateItem(currentIndex);
        setInterval(() => {
            currentIndex = (currentIndex + 1) % listItems.length;
            activateItem(currentIndex)
        }, 2000)
    };
    const initializeFeatures = function() {
        const scrollingImages = document.querySelector('.with-scrolling-image-template');
        if (scrollingImages) {
            const mm = gsap.matchMedia();
            mm.add('(min-width: 1024px)', () => {
                gsap.from('.second-image', {
                    y: 600,
                    scrollTrigger: {
                        trigger: '.with-scrolling-image-template',
                        start: 'top center',
                        end: 'bottom center',
                        scrub: 3,
                    },
                });
                gsap.from('.first-image', {
                    y: -200,
                    scrollTrigger: {
                        trigger: '.with-scrolling-image-template',
                        start: 'top center',
                        end: 'bottom center',
                        scrub: 3,
                    },
                })
            });
            mm.add('(max-width: 1023px)', () => {
                gsap.from('.second-image', {
                    y: 500,
                    scrollTrigger: {
                        trigger: '.with-scrolling-image-template',
                        start: 'top center',
                        end: 'bottom center',
                        scrub: 3,
                    },
                });
                gsap.from('.first-image', {
                    y: 800,
                    scrollTrigger: {
                        trigger: '.with-scrolling-image-template',
                        start: 'top center',
                        end: 'bottom center',
                        scrub: 3,
                    },
                })
            });

            function initSplit() {
                if (splitInstance) {
                    splitInstance.revert()
                }
                splitInstance = new SplitType('.animated-text', {
                    types: 'lines, words'
                });
                setTimeout(() => {
                    $('.animated-text').css('opacity', '1');
                    const transitionLines = $('.animated-text .line');
                    transitionLines.each((i, line) => {
                        gsap.to($(line).find('.word'), {
                            y: 0,
                            delay: 0.175 * i,
                            ease: 'power2.out',
                            scrollTrigger: {
                                trigger: '.with-scrolling-image-template',
                                start: 'top center',
                                end: 'top center',
                            },
                        })
                    })
                }, 200)
            }
            initSplit();
            new SplitType('.animated-text', {
                types: 'lines, words'
            });
            $(window).on('resize', debounce(function() {
                const currentWidth = $(window).width();
                if (currentWidth !== previousWidth) {
                    $('.animated-text').css('opacity', '0');
                    $('.animated-text .word').css('transform', 'translateY(100%)');
                    initSplit()
                }
            }, 200))
        }
    };
    const initializeParallaxBlock = function() {
        const parallaxImages = document.querySelector('.with-parallax-images');
        if (parallaxImages) {
            document.querySelectorAll('.with-parallax-images').forEach((container) => {
                const images = container.querySelectorAll('.parallax-image');
                images.forEach((img, i) => {
                    gsap.from(img, {
                        y: 40 * i,
                        ease: 'none',
                        scrollTrigger: {
                            trigger: parallaxImages,
                            start: 'top bottom',
                            end: 'bottom+=100% bottom',
                            scrub: 2,
                        },
                    })
                });
                const mm = gsap.matchMedia();
                mm.add('(min-width: 1024px)', () => {
                    images.forEach((innerImg) => {
                        gsap.to(innerImg.querySelector('img'), {
                            y: 80,
                            ease: 'none',
                            scrollTrigger: {
                                trigger: container,
                                start: 'top bottom',
                                end: 'bottom+=100% bottom',
                                scrub: !0,
                            },
                        })
                    })
                })
            })
        }
    };
    const initializeStickyAccordion = function() {
        if (window.matchMedia('(min-width: 768px)').matches) {
            const $block = $('.iwa-wrapper');
            const $items = $block.find('.accordion-item');
            const $images = $block.find('.accordion-image');
            let activeIndex = 0;
            if (!$block.length || !$items.length) {
                return
            }
            const isDesktop = window.matchMedia('(min-width: 1024px)').matches;
            const animationDuration = isDesktop ? 500 : 300;
            const scrollMultiplier = isDesktop ? 80 : 30;
            $items.find('.accordion-counter, .accordion-description').hide();
            $images.removeClass('opacity-100 z-10 active').addClass('opacity-0 z-0');
            const $firstItem = $items.eq(0);
            $firstItem.find('.accordion-counter, .accordion-description').show();
            $firstItem.find('.accordion-title').removeClass('text-systemgrey-40').addClass('text-black md:mb-[6px] lg:mb-[10px]');
            $images.filter('[data-index="0"]').addClass('opacity-100 z-10 active').removeClass('opacity-0 z-0');
            activeIndex = 0;
            const navHeight = $('.dbtm-main-nav').outerHeight() || 0;
            const bannerHeight = $('.cta-banner').outerHeight() || 0;
            const bachelorsNavHeight = $('.bachelors-degree-nav').outerHeight() || 0;
            const totalOffset = navHeight + bannerHeight + bachelorsNavHeight;
            ScrollTrigger.create({
                trigger: $block[0],
                start: `top-=${ totalOffset } top`,
                end: () => `+=${ $items.length * scrollMultiplier }%`,
                pin: !0,
                scrub: !0,
                markers: !1,
                onUpdate: (self) => {
                    const progress = self.progress;
                    const itemProgress = progress * $items.length;
                    const newIndex = Math.min(Math.floor(itemProgress + 0.2), $items.length - 1);
                    if (newIndex !== activeIndex) {
                        const $item = $items.eq(newIndex);
                        const $title = $item.find('.accordion-title');
                        const $counter = $item.find('.accordion-counter');
                        const $description = $item.find('.accordion-description');
                        $items.each(function(i, otherEl) {
                            const $other = $(otherEl);
                            $other.find('.accordion-counter, .accordion-description').stop().slideUp(animationDuration);
                            $other.find('.accordion-title').removeClass('text-black md:mb-[6px] lg:mb-[10px]').addClass('text-systemgrey-40')
                        });
                        $title.removeClass('text-systemgrey-40').addClass('text-black md:mb-[6px] lg:mb-[10px]');
                        $counter.stop().slideDown(animationDuration);
                        $description.stop().slideDown(animationDuration);
                        if (isDesktop) {
                            $images.each(function(i, img) {
                                $(img).toggleClass('opacity-100 z-10 active', i === newIndex).toggleClass('opacity-0 z-0', i !== newIndex)
                            })
                        } else {
                            $images.removeClass('active');
                            $images.filter(`[data-index="${ newIndex }"]`).addClass('active')
                        }
                        activeIndex = newIndex
                    }
                },
            })
        }
    };
    const initImageCarousels = function() {
        const $carousels = $('.ic-featured-images');
        if ($carousels.length === 0) {
            return
        }
        $carousels.each(function(groupIndex) {
            const $group = $(this);
            const $images = $group.find('.ic-image');
            const total = $images.length;
            let current = 0;
            const delay = 3000;
            const steps = 100;
            const stepDuration = delay / steps;

            function resetAllBars() {
                for (let i = 0; i < total; i++) {
                    const $bar = $group.find(`.ic-progress-segment-${ groupIndex }-${ i }`);
                    $bar.css('width', '0%')
                }
            }

            function updateProgress(index, callback) {
                const $currentBar = $group.find(`.ic-progress-segment-${ groupIndex }-${ index }`);
                let progress = 0;
                $currentBar.css('width', '0%');
                const interval = setInterval(() => {
                    progress += 1;
                    $currentBar.css('width', `${ progress }%`);
                    if (progress >= 100) {
                        clearInterval(interval);
                        if (typeof callback === 'function') {
                            callback()
                        }
                    }
                }, stepDuration)
            }

            function showSlide(index) {
                if (index === 0) {
                    resetAllBars()
                }
                $images.css({
                    opacity: 0,
                    zIndex: 0
                });
                $images.eq(index).css({
                    opacity: 1,
                    zIndex: 10
                });
                updateProgress(index, () => {
                    current = (current + 1) % total;
                    showSlide(current)
                })
            }
            showSlide(current)
        })
    };
    const initYearGalleryToggle = function() {
        const $galleries = $('.gallery-block');
        if ($galleries.length === 0) {
            return
        }
        $galleries.each(function() {
            const $gallery = $(this);
            const $buttons = $gallery.find('.g-year-selector');
            const $groups = $gallery.find('.g-year-group');
            const $firstButton = $buttons.first();
            const defaultYear = $firstButton.data('year');
            $buttons.removeClass('active');
            $firstButton.addClass('active');
            $groups.each(function() {
                const groupYear = $(this).data('year');
                $(this).toggle(groupYear === defaultYear)
            });
            $buttons.on('click', function() {
                const selectedYear = $(this).data('year');
                $buttons.removeClass('active');
                $(this).addClass('active');
                $groups.each(function() {
                    const groupYear = $(this).data('year');
                    $(this).toggle(groupYear === selectedYear)
                })
            })
        });
        initGalleryModal()
    };
    const initGalleryModal = function() {
        let textSub = 'Subject';
        const currentLang = document.documentElement.getAttribute('lang');
        if (currentLang === 'th') {
            textSub = 'วิชา'
        }
        $('.gallery-label').each(function() {
            $(this).find('.subject-prefix').text(textSub + ': ')
        });
        $('.gallery-block').each(function() {
            const $gallery = $(this);
            const $modal = $gallery.find('.gallery-modal');
            const $modalInner = $modal.find('.modal-inner');
            const $modalImage = $modal.find('.modal-image');
            const $masthead = $('#masthead');
            const $closeBtn = $modal.find('.close-gallery');
            $gallery.find('.g-image-container').on('click', function() {
                const $img = $(this).find('.gallery-image');
                const src = $img.attr('src');
                const subject = $(this).data('subject');
                const orientation = $(this).data('orientation');
                const orientationClass = `g-${ orientation }`;
                $modalImage.attr('src', src);
                $('.g-subject-value').text(textSub + ': ' + (subject || ''));
                $modalInner.removeClass('g-landscape g-portrait').addClass(orientationClass);
                $('.g-image-wrapper').removeClass('g-landscape g-portrait').addClass(orientationClass);
                $('.g-subject-container').removeClass('g-landscape g-portrait').addClass(orientationClass);
                $modal.removeClass('hidden');
                $('body').addClass('modal-open');
                if (window.lenis) {
                    window.lenis.stop()
                }
                $masthead.addClass('-mt-[130px]');
                setTimeout(() => {
                    $modalInner.removeClass('translate-y-full').addClass('translate-y-0')
                }, 10)
            });

            function closeModal() {
                $modalInner.removeClass('translate-y-0').addClass('translate-y-full');
                $masthead.removeClass('-mt-[130px]');
                setTimeout(() => {
                    $modal.addClass('hidden');
                    $modalImage.attr('src', '');
                    $('body').removeClass('modal-open');
                    if (window.lenis) {
                        window.lenis.start()
                    }
                }, 300)
            }
            if (window.matchMedia('(min-width: 1024px)').matches) {
                $modal.on('click', function() {
                    closeModal()
                })
            }
            if (window.matchMedia('(max-width: 1023px)').matches) {
                $closeBtn.on('click', function(e) {
                    e.stopPropagation();
                    closeModal()
                })
            }
        })
    };
    const initializeStickyTemplate = function() {
        const scrollingImages = document.querySelector('.sticky-template');
        const scrollingImagesTablet = document.querySelector('.sticky-template-tablet');
        const scrollingImagesMobile = document.querySelector('.sticky-template-mobile');
        if (scrollingImages === 0 || scrollingImagesTablet === 0 || scrollingImagesMobile === 0) {
            return
        }
        $(scrollingImages).each(function(i, el) {
            $(el).find('.sticky').each(function(index, element) {
                const $wrapper = $(element);
                const $info = $wrapper.find('.image-info');
                const $image = $wrapper.find('.sticky-image');
                gsap.to($info[0], {
                    opacity: 1,
                    ease: 'power1.out',
                    scrollTrigger: {
                        trigger: $image[0],
                        start: 'top top',
                        end: 'top top',
                        scrub: 1,
                    },
                });
                gsap.to('.not-active-text', {
                    opacity: 1,
                    scrollTrigger: {
                        trigger: '.not-active-image',
                        start: 'top top',
                        end: 'top top',
                        scrub: 1,
                    },
                })
            })
        });
        $(scrollingImagesTablet).each(function(i, el) {
            const imageSlides = $(el).find('.image-wrapper-tablet');
            const allBars = $(el).find('.bar-tb');
            const totalBars = allBars.length;
            if (imageSlides.length > 1) {
                let currentSlide = 0;
                setInterval(function() {
                    $(imageSlides).eq(currentSlide).removeClass('st-active').addClass('st-not-active');
                    currentSlide = (currentSlide + 1) % imageSlides.length;
                    $(imageSlides).eq(currentSlide).removeClass('st-not-active').addClass('st-active')
                }, 3000)
            }
            if (totalBars > 1) {
                let currentBar = 0;

                function activateBar(index) {
                    const $bar = $(allBars).eq(index);
                    if (!$bar.hasClass('bar-active')) {
                        $bar.removeClass('bar-not-active').addClass('bar-active')
                    }
                }
                activateBar(currentBar);
                currentBar++;
                setInterval(function() {
                    if (currentBar >= totalBars) {
                        $(allBars).removeClass('bar-active').addClass('bar-not-active');
                        currentBar = 0;
                        setTimeout(function() {
                            activateBar(currentBar);
                            currentBar++
                        }, 100);
                        return
                    }
                    activateBar(currentBar);
                    currentBar++
                }, 3000)
            }
        });
        $(scrollingImagesMobile).each(function(i, el) {
            const imageSlides = $(el).find('.image-wrapper-mobile');
            const allBars = $(el).find('.bar-mb');
            const totalBars = allBars.length;
            if (imageSlides.length > 1) {
                let currentSlide = 0;
                setInterval(function() {
                    $(imageSlides).eq(currentSlide).removeClass('st-active').addClass('st-not-active');
                    currentSlide = (currentSlide + 1) % imageSlides.length;
                    $(imageSlides).eq(currentSlide).removeClass('st-not-active').addClass('st-active')
                }, 3000)
            }
            if (totalBars > 1) {
                let currentBar = 0;

                function activateBar(index) {
                    const $bar = $(allBars).eq(index);
                    if (!$bar.hasClass('bar-active')) {
                        $bar.removeClass('bar-not-active').addClass('bar-active')
                    }
                }
                activateBar(currentBar);
                currentBar++;
                setInterval(function() {
                    if (currentBar >= totalBars) {
                        $(allBars).removeClass('bar-active').addClass('bar-not-active');
                        currentBar = 0;
                        setTimeout(function() {
                            activateBar(currentBar);
                            currentBar++
                        }, 100);
                        return
                    }
                    activateBar(currentBar);
                    currentBar++
                }, 3000)
            }
        })
    };
    const initializeIWAMobileToggle = function() {
        const $container = $('.iwa-mobile');
        if (!$container.length) {
            return
        }
        const $block = $('.iwa-toggle-block');
        const $images = $('.iwa-mobile-image .iwa-image');
        if ($block.length) {
            $block.find('.iwa-wrapper').on('click', function() {
                const $this = $(this);
                const $desc = $this.find('.iwa-description');
                const $icon = $this.find('.iwa-icon');
                const $title = $this.find('.iwa-title');
                const index = $this.index();
                $block.find('.iwa-wrapper.iwa-active').not($this).removeClass('iwa-active').find('.iwa-description').stop().slideUp();
                $block.find('.iwa-wrapper').not($this).find('.iwa-icon').removeClass('rotate-45');
                $block.find('.iwa-wrapper').not($this).find('.iwa-title').removeClass('text-black').addClass('text-systemgrey-40');
                $this.toggleClass('iwa-active');
                $desc.stop().slideToggle();
                $icon.toggleClass('rotate-45');
                $title.toggleClass('text-systemgrey-40 text-black');
                $images.addClass('hidden');
                $images.filter(`[data-index="${ index }"]`).removeClass('hidden')
            });
            const $firstItem = $block.find('.iwa-wrapper').eq(0);
            $firstItem.trigger('click')
        }
    };
    $(document).ready(function() {
        initBulletVerticalAlign();
        initializeFeatures();
        initializeParallaxBlock();
        initializeStickyAccordion();
        initImageCarousels();
        initYearGalleryToggle();
        setTimeout(function() {
            initializeStickyTemplate()
        }, 100);
        initializeIWAMobileToggle()
    });
    if (window.acf) {
        window.acf.addAction('render_block_preview/type=gl_features', initBulletVerticalAlign);
        window.acf.addAction('render_block_preview/type=gl_features', initializeFeatures);
        window.acf.addAction('render_block_preview/type=gl_features', initializeParallaxBlock);
        window.acf.addAction('render_block_preview/type=gl_features', initializeStickyAccordion);
        window.acf.addAction('render_block_preview/type=gl_features', initImageCarousels);
        window.acf.addAction('render_block_preview/type=gl_features', initYearGalleryToggle);
        window.acf.addAction('render_block_preview/type=gl_features', initializeStickyTemplate)
    }
}(jQuery));
(function($) {
    const initializeActivities = function() {
        const activityList = document.querySelector('.activity-list-block .al-list');
        if (!activityList) {
            return
        }
        let paged = 1;
        let loading = !1;
        let maxPages = 1;

        function getDeviceType() {
            const width = window.innerWidth;
            if (width < 768) {
                return 'mobile'
            }
            if (width < 1024) {
                return 'tablet'
            }
            return 'desktop'
        }
        const deviceType = getDeviceType();

        function loadActivities(device) {
            if ($('body').hasClass('wp-admin') || loading) {
                return
            }
            loading = !0;
            $.ajax({
                url: ajaxVar.ajaxUrl,
                type: 'post',
                dataType: 'json',
                data: {
                    action: 'load_activities',
                    device,
                    nonce: ajaxVar.nonce,
                    paged,
                },
                success(response) {
                    if (!response.success || !response.data.html) {
                        return
                    }
                    const data = response.data;
                    maxPages = data.max_pages;
                    const $items = $(data.html);
                    $items.addClass('fade-in-up');
                    $('.activity-list-block .al-list').append($items);
                    setTimeout(() => {
                        $items.addClass('visible')
                    }, 50);
                    loading = !1;
                    paged++;
                    setTimeout(() => ScrollTrigger.refresh(), 500)
                },
            })
        }
        loadActivities(deviceType);
        window.addEventListener('scroll', function() {
            if (loading || paged > maxPages) {
                return
            }
            const scrollBottom = window.scrollY + window.innerHeight;
            const docHeight = document.body.offsetHeight;
            if (scrollBottom >= docHeight - 600) {
                loadActivities(deviceType)
            }
        })
    };
    $(document).ready(function() {
        initializeActivities()
    })
}(jQuery));
(function($) {
    function initializeNewsAndEventTab() {
        const $section = $('.gl-news-and-event-post-section');
        if ($section.length === 0) {
            return
        }
        $section.each(function() {
            const $container = $(this);
            const $content = $container.find('.neep-content');
            const $typeTabs = $content.find('.neep-type-filter button.type');
            const $statusTabs = $content.find('.neep-status-filter button.date');
            const $mobileStatusTabs = $content.find('.nee-mobile-options button.mobile-status');
            const $list = $content.find('.neep-list');
            const postIds = $container.data('post-ids');
            const defaultStatus = $container.data('default-status') || 'current';
            const nonce = $list.data('nonce');
            const $mobileSelector = $content.find('.neep-mobile-selector');
            const $mobileOptions = $content.find('.nee-mobile-options');
            const $mobileSelectedText = $mobileSelector.find('.neep-mobile-selected');
            const $mobileIcon = $mobileSelector.find('.neep-dropdown-icon');
            const $loader = $list.find('.neep-loader');
            let loading = !1;
            $mobileOptions.addClass('hidden');
            $statusTabs.removeClass('active');
            $statusTabs.filter('[data-filter="' + defaultStatus + '"]').addClass('active');
            $mobileStatusTabs.removeClass('active');
            $mobileStatusTabs.filter('[data-filter="' + defaultStatus + '"]').addClass('active');
            const $activeStatus = $statusTabs.filter('.active').first();
            if ($activeStatus.length) {
                $mobileSelectedText.text($activeStatus.text().trim())
            }

            function revealNextItems() {
                if (loading) {
                    return
                }
                const $hiddenItems = $list.find('.neep-item[data-lazy="true"]');
                if ($hiddenItems.length === 0) {
                    $(window).off('scroll.neep-reveal');
                    $loader.addClass('hidden');
                    return
                }
                loading = !0;
                $loader.removeClass('hidden');
                setTimeout(() => {
                    const windowWidth = $(window).width();
                    let batchSize = 1;
                    if (windowWidth >= 1024) {
                        batchSize = 3
                    } else if (windowWidth >= 768) {
                        batchSize = 2
                    }
                    const allIndexes = [];
                    $hiddenItems.each(function() {
                        const idx = $(this).data('index');
                        if (!allIndexes.includes(idx)) {
                            allIndexes.push(idx)
                        }
                    });
                    allIndexes.sort((a, b) => a - b);
                    const revealedIndexes = allIndexes.slice(0, batchSize);
                    const itemsToReveal = $hiddenItems.filter(function() {
                        return revealedIndexes.includes($(this).data('index'))
                    });
                    itemsToReveal.each(function() {
                        const $item = $(this);
                        $item.removeAttr('data-lazy');
                        if (windowWidth >= 1024) {
                            $item.removeClass('hidden lg:block')
                        } else if (windowWidth >= 768) {
                            $item.removeClass('hidden md:block')
                        } else {
                            $item.removeClass('hidden')
                        }
                        $item.addClass('fade-in-up-initial')
                    });
                    setTimeout(() => {
                        itemsToReveal.each(function() {
                            $(this).addClass('fade-in-up-active')
                        });
                        $loader.addClass('hidden');
                        loading = !1;
                        const newTotalHidden = $list.find('.neep-item[data-lazy="true"]').length;
                        if (newTotalHidden === 0) {
                            $(window).off('scroll.neep-reveal')
                        }
                    }, 50)
                }, 300)
            }

            function handleScrollReveal() {
                const $hiddenItems = $list.find('.neep-item[data-lazy="true"]');
                if ($hiddenItems.length === 0 || loading) {
                    return
                }
                const windowWidth = $(window).width();
                let $activeColumn;
                let $lastVisibleItem;
                if (windowWidth >= 1024) {
                    $activeColumn = $list.find('.desktop-column').first();
                    $lastVisibleItem = $activeColumn.find('.neep-item').not('[data-lazy="true"]').last()
                } else if (windowWidth >= 768) {
                    $activeColumn = $list.find('.tablet-column');
                    let maxBottom = 0;
                    $activeColumn.find('.neep-item').not('[data-lazy="true"]').each(function() {
                        const bottom = $(this).offset().top + $(this).outerHeight();
                        if (bottom > maxBottom) {
                            maxBottom = bottom;
                            $lastVisibleItem = $(this)
                        }
                    })
                } else {
                    $activeColumn = $list.find('.mobile-column');
                    $lastVisibleItem = $activeColumn.find('.neep-item').not('[data-lazy="true"]').last()
                }
                if (!$lastVisibleItem || !$lastVisibleItem.length) {
                    return
                }
                const lastItemBottom = $lastVisibleItem.offset().top + $lastVisibleItem.outerHeight();
                const scrollBottom = $(window).scrollTop() + $(window).height();
                let buffer = 20;
                if (windowWidth >= 1024) {
                    buffer = 150
                } else if (windowWidth >= 768) {
                    buffer = 200
                }
                if (scrollBottom >= (lastItemBottom + buffer)) {
                    revealNextItems()
                }
            }

            function filterItems() {
                const activeType = $typeTabs.filter('.active').first().data('filter');
                const activeDesktopStatus = $statusTabs.filter('.active').first().data('filter');
                const activeMobileStatus = $mobileStatusTabs.filter('.active').first().data('filter');
                const activeStatus = activeDesktopStatus || activeMobileStatus;
                if (!postIds || !nonce) {
                    return
                }
                $(window).off('scroll.neep-reveal');
                $loader.removeClass('hidden');
                $.ajax({
                    url: ajaxVar.ajaxUrl,
                    type: 'POST',
                    data: {
                        action: 'gl_ajax_filter_news_events',
                        security: nonce,
                        post_ids: postIds,
                        type: activeType,
                        status: activeStatus,
                        today: (function() {
                            const now = new Date();
                            const year = now.getFullYear();
                            const month = String(now.getMonth() + 1).padStart(2, '0');
                            const day = String(now.getDate()).padStart(2, '0');
                            return year + '-' + month + '-' + day
                        }()),
                    },
                    success(response) {
                        $list.html(response);
                        const $newLoader = $list.find('.neep-loader');
                        $newLoader.addClass('hidden');
                        const $visibleItems = $list.find('.neep-item').not('[data-lazy="true"]');
                        $visibleItems.addClass('fade-in-up-initial');
                        setTimeout(() => {
                            $visibleItems.each(function(index) {
                                setTimeout(() => {
                                    $(this).addClass('fade-in-up-active')
                                }, index * 80)
                            })
                        }, 50);
                        $(window).on('scroll.neep-reveal', handleScrollReveal);
                        handleScrollReveal()
                    },
                    error() {
                        $list.html('<p class="col-span-full p-4 text-center">Failed to load content. Please try again.</p>');
                        $loader.addClass('hidden')
                    },
                })
            }
            $typeTabs.off('click').on('click', function() {
                $typeTabs.removeClass('active');
                $(this).addClass('active');
                $('.neep-list').removeClass('min-h-[80vh]');
                filterItems()
            });
            $statusTabs.off('click').on('click', function() {
                const selectedStatus = $(this).data('filter');
                $statusTabs.removeClass('active');
                $(this).addClass('active');
                $mobileStatusTabs.removeClass('active');
                $mobileStatusTabs.filter('[data-filter="' + selectedStatus + '"]').addClass('active');
                $mobileSelectedText.text($(this).text());
                $mobileOptions.addClass('hidden');
                $mobileIcon.removeClass('rotate-180');
                $('.neep-list').removeClass('min-h-[80vh]');
                filterItems()
            });
            $mobileStatusTabs.off('click').on('click', function() {
                const selectedStatus = $(this).data('filter');
                const selectedText = $(this).text();
                $mobileStatusTabs.removeClass('active');
                $(this).addClass('active');
                $mobileSelectedText.text(selectedText);
                $mobileOptions.addClass('hidden');
                $mobileIcon.removeClass('rotate-180');
                $statusTabs.removeClass('active');
                $statusTabs.filter('[data-filter="' + selectedStatus + '"]').addClass('active');
                filterItems()
            });
            $mobileSelector.off('click').on('click', function(e) {
                e.preventDefault();
                $mobileOptions.toggleClass('hidden');
                $mobileIcon.toggleClass('rotate-180')
            });
            $(document).on('click', function(e) {
                if (!$mobileSelector.is(e.target) && $mobileSelector.has(e.target).length === 0 && !$mobileOptions.is(e.target) && $mobileOptions.has(e.target).length === 0) {
                    $mobileOptions.addClass('hidden');
                    $mobileIcon.removeClass('rotate-180')
                }
            });
            $(window).on('scroll.neep-reveal', handleScrollReveal);
            if ($(window).width() >= 768 && $(window).width() < 1024) {
                $list.find('.neep-item[data-lazy="true"]').each(function() {
                    if ($(this).data('index') === 3) {
                        $(this).removeAttr('data-lazy');
                        $(this).removeClass('hidden md:block')
                    }
                })
            }
            $list.find('.neep-item').not('[data-lazy="true"]').addClass('fade-in-up-initial fade-in-up-active');
            $(window).on('scroll.neep-reveal', handleScrollReveal);
            handleScrollReveal()
        })
    }
    $(document).ready(function() {
        initializeNewsAndEventTab()
    });
    if (window.acf) {
        window.acf.addAction('render_block_preview/type=gl_news_and_event', initializeNewsAndEventTab)
    }
}(jQuery));
(function($) {
    function initializeGalleryRotation() {
        const $frames = $('.cta-frame');
        if ($frames.length === 0) {
            return
        }
        let current = 0;
        setInterval(() => {
            $frames.eq(current).removeClass('active');
            current = (current + 1) % $frames.length;
            $frames.eq(current).addClass('active')
        }, 700)
    }
    const initalizeSimpleCTA = function() {
        const simpleCTA = document.querySelector('.gl-cta-simple .text-container-mb');
        if (!simpleCTA) {
            return
        }
        let $items = $(simpleCTA).children();
        const originalItemsCount = $items.length;
        let currentIndex = 0;
        if (originalItemsCount <= 1) {
            return
        }
        const $firstClone = $items.first().clone();
        $firstClone.removeClass('top-1/2 -translate-y-1/2').addClass('top-full');
        $(simpleCTA).append($firstClone);
        $items = $(simpleCTA).children();
        const totalItems = $items.length;

        function animateNext() {
            const $current = $items.eq(currentIndex);
            const nextIndex = currentIndex + 1;
            const $next = $items.eq(nextIndex);
            const tl = gsap.timeline({
                onComplete: () => {
                    if (nextIndex === totalItems - 1) {
                        setTimeout(function() {
                            currentIndex = 0;
                            const $first = $items.eq(0);
                            gsap.set($next, {
                                clearProps: 'all',
                            });
                            gsap.set($first, {
                                clearProps: 'all',
                            });
                            setTimeout(animateNext, 1000)
                        }, 1000)
                    } else {
                        currentIndex = nextIndex;
                        setTimeout(animateNext, 1000)
                    }
                },
            });
            tl.to($current, {
                top: '-100%',
                y: '0%',
                duration: 0.6,
                ease: 'power4.Out',
            });
            tl.fromTo($next, {
                top: '100%',
                y: '0%',
                ease: 'power4.In',
            }, {
                top: '50%',
                y: '-50%',
                duration: 0.6,
                ease: 'power4.In',
            }, '-=0.6')
        }
        setTimeout(animateNext, 1000)
    };
    $(document).ready(function() {
        initializeGalleryRotation();
        initalizeSimpleCTA()
    });
    if (window.acf) {
        window.acf.addAction('render_block_preview/type=gl-cta', initializeGalleryRotation)
    }
}(jQuery))